if (!function_exists('fin_t')) {
  function fin_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('fin_h')) {
  function fin_h($key, $fallback = '') { return htmlspecialchars((string) fin_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('fin_js')) {
  function fin_js($key, $fallback = '') { return json_encode(fin_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$initialOutputBufferLevel=ob_get_level();ob_start();session_start();include "../../inc/config.php";require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";require_once "incoming_payment_lib.php";session_check_json();
function ip_json($s,$m='',$e=array()){header('Content-Type: application/json');echo json_encode(array_merge(array('status'=>$s,'message'=>$m),$e));exit;}
function ip_params(){ $st=$_REQUEST['start_date']??date('Y-m-01');$en=$_REQUEST['end_date']??date('Y-m-d');if(!ip_valid_date($st)||!ip_valid_date($en)||$st>$en)throw new Exception('Periode tanggal tidak valid.');return array($st,$en,trim($_REQUEST['status']??''),trim($_REQUEST['customer_code']??''));}
function ip_list($db,$st,$en,$status,$cust){$w="ip.posting_date BETWEEN ? AND ?";$p=array($st,$en);if($status!==''){$w.=" AND ip.status=?";$p[]=$status;}if($cust!==''){$w.=" AND ip.customer_code=?";$p[]=$cust;}return $db->query("SELECT ip.*,c.nama customer_name,ba.nama_rek bank_account_name,aa.nama_rek ar_account_name,jh.no_jurnal FROM erp_incoming_payment ip LEFT JOIN customer c ON c.kode_pemasok=ip.customer_code LEFT JOIN rekening ba ON ba.no_rek=ip.bank_account LEFT JOIN rekening aa ON aa.no_rek=ip.ar_account LEFT JOIN jurnal_header jh ON jh.id=ip.journal_header_id WHERE $w ORDER BY ip.posting_date DESC,ip.id DESC",$p);}
$act=$_GET['act']??'';
try{
switch($act){
case 'get_no':ip_json('success','OK',array('no'=>ip_next_no($db)));break;
case 'invoice_info':
  $id=(int)($_GET['id']??0);$inv=$db->fetch("SELECT si.*,c.nama customer_name,c.kode_pemasok customer_code,COALESCE((SELECT SUM(amount) FROM erp_incoming_payment ip WHERE ip.sales_invoice_id=si.id_sales AND ip.status='POSTED'),0) paid_amount FROM sales_invoice si LEFT JOIN customer c ON c.kode_pemasok=si.bill_to OR c.kode_pemasok=si.ship_to WHERE si.id_sales=? LIMIT 1",array($id));if(!$inv)throw new Exception('Invoice tidak ditemukan.');$inv->open_amount=max(0,(float)$inv->gross_amount-(float)$inv->paid_amount);ip_json('success','OK',array('data'=>$inv));break;
case 'save':case 'post':
  $id=(int)($_POST['id']??0);
  if($act==='post'&&$id&&empty($_POST['incoming_payment_no'])){$p=$db->fetch("SELECT * FROM erp_incoming_payment WHERE id=? LIMIT 1",array($id));if(!$p)throw new Exception('Incoming payment tidak ditemukan.');if($p->status!=='DRAFT')throw new Exception('Hanya draft yang bisa diposting.');ip_post_to_gl($db,$p);ip_json('success','Incoming payment berhasil diposting.',array('id'=>$id));}
  $no=trim($_POST['incoming_payment_no']??'');if($no==='')$no=ip_next_no($db);$doc=trim($_POST['document_date']);$post=trim($_POST['posting_date']);$val=trim($_POST['value_date']??'');if(!ip_valid_date($doc)||!ip_valid_date($post)||($val!==''&&!ip_valid_date($val)))throw new Exception('Tanggal tidak valid.');if($act==='post'){$per=ip_period_open($db,$post);if($per!==true)throw new Exception($per);}
  $cust=trim($_POST['customer_code']);if(!$db->fetch("SELECT id_customer FROM customer WHERE kode_pemasok=? LIMIT 1",array($cust)))throw new Exception('Customer tidak valid.');
  $bank=trim($_POST['bank_account']);$ar=trim($_POST['ar_account']);ip_account_leaf($db,$bank,'Bank account');ip_account_leaf($db,$ar,'AR account');$amount=ip_amount($_POST['amount']);if($amount<=0)throw new Exception('Amount wajib lebih dari nol.');
  $method=$_POST['payment_method']??'TRANSFER';if(!in_array($method,array('TRANSFER','GIRO','CASH','VIRTUAL_ACCOUNT','OTHER')))$method='TRANSFER';
  $invoiceId=($_POST['sales_invoice_id']!=='')?(int)$_POST['sales_invoice_id']:null;$invoiceNo=trim($_POST['sales_invoice_no']??'');
  $data=array('incoming_payment_no'=>$no,'customer_code'=>$cust,'sales_invoice_id'=>$invoiceId,'sales_invoice_no'=>$invoiceNo,'document_date'=>$doc,'posting_date'=>$post,'value_date'=>$val!==''?$val:null,'bank_account'=>$bank,'ar_account'=>$ar,'amount'=>$amount,'currency'=>strtoupper(trim($_POST['currency']?:'IDR')),'kurs'=>ip_amount($_POST['kurs']?:1),'payment_method'=>$method,'bank_reference'=>trim($_POST['bank_reference']),'external_reference'=>trim($_POST['external_reference']),'description'=>trim($_POST['description']),'updated_by'=>ip_user(),'updated_at'=>date('Y-m-d H:i:s'));
  if($id){$old=$db->fetch("SELECT * FROM erp_incoming_payment WHERE id=? LIMIT 1",array($id));if(!$old)throw new Exception('Incoming payment tidak ditemukan.');if($old->status!=='DRAFT')throw new Exception('Hanya draft yang boleh diedit.');$db->update('erp_incoming_payment',$data,'id',$id);}else{if($db->fetch("SELECT id FROM erp_incoming_payment WHERE incoming_payment_no=? LIMIT 1",array($no)))throw new Exception('Nomor sudah digunakan.');$data['status']='DRAFT';$data['created_by']=ip_user();$data['created_at']=date('Y-m-d H:i:s');$db->insert('erp_incoming_payment',$data);$id=$db->last_insert_id();}
  if($act==='post'){$p=$db->fetch("SELECT * FROM erp_incoming_payment WHERE id=? LIMIT 1",array($id));ip_post_to_gl($db,$p);ip_json('success','Incoming payment berhasil disimpan dan diposting.',array('id'=>$id));}
  ip_json('success','Draft incoming payment berhasil disimpan.',array('id'=>$id));break;
case 'get':$id=(int)($_GET['id']??0);$r=$db->fetch("SELECT * FROM erp_incoming_payment WHERE id=? LIMIT 1",array($id));if(!$r)throw new Exception('Incoming payment tidak ditemukan.');ip_json('success','OK',array('data'=>$r));break;
case 'filter':
  list($st,$en,$status,$cust)=ip_params();$rows=ip_list($db,$st,$en,$status,$cust);$html='';$total=0;$posted=0;$draft=0;$n=0;foreach($rows as $r){$n++;$total+=(float)$r->amount;if($r->status==='POSTED')$posted+=(float)$r->amount;if($r->status==='DRAFT')$draft+=(float)$r->amount;$cls=$r->status==='POSTED'?'success':($r->status==='REVERSED'?'danger':'warning');$actn='<div class="btn-group btn-group-xs"><button class="btn btn-info ip-detail" data-id="'.$r->id.'"><i class="fa fa-search"></i></button>';if($r->status==='DRAFT')$actn.='<button class="btn btn-primary ip-edit" data-id="'.$r->id.'"><i class="fa fa-pencil"></i></button><button class="btn btn-success ip-post" data-id="'.$r->id.'"><i class="fa fa-check"></i></button>';$actn.='</div>';$html.='<tr><td>'.$n.'</td><td>'.ip_h($r->posting_date).'</td><td>'.ip_h($r->incoming_payment_no).'</td><td>'.ip_h($r->customer_code.' - '.$r->customer_name).'</td><td>'.ip_h($r->sales_invoice_no).'</td><td><span class="label label-'.$cls.'">'.ip_h($r->status).'</span></td><td>'.ip_h($r->bank_account.' - '.$r->bank_account_name).'</td><td>'.ip_h($r->payment_method).'</td><td>'.ip_h($r->bank_reference).'</td><td class="text-right">'.ip_num($r->amount).'</td><td>'.ip_h($r->currency).'</td><td>'.$actn.'</td></tr>';}if($n===0)$html='<tr><td colspan="12" class="text-center text-muted">Tidak ada data.</td></tr>';ip_json('success','OK',array('html'=>$html,'total'=>ip_num($total),'posted'=>ip_num($posted),'draft'=>ip_num($draft),'count'=>$n));break;
case 'detail':$id=(int)($_GET['id']??0);$r=$db->fetch("SELECT ip.*,c.nama customer_name,ba.nama_rek bank_account_name,aa.nama_rek ar_account_name,jh.no_jurnal FROM erp_incoming_payment ip LEFT JOIN customer c ON c.kode_pemasok=ip.customer_code LEFT JOIN rekening ba ON ba.no_rek=ip.bank_account LEFT JOIN rekening aa ON aa.no_rek=ip.ar_account LEFT JOIN jurnal_header jh ON jh.id=ip.journal_header_id WHERE ip.id=? LIMIT 1",array($id));if(!$r)throw new Exception('Incoming payment tidak ditemukan.');$html='<table class="table table-bordered table-condensed"><tr><th>'.fin_h('common_no', 'No').'</th><td>'.ip_h($r->incoming_payment_no).'</td><th>Journal</th><td>'.ip_h($r->no_jurnal).'</td></tr><tr><th>'.fin_h('finance_customer', 'Customer').'</th><td>'.ip_h($r->customer_code.' - '.$r->customer_name).'</td><th>'.fin_h('finance_invoice', 'Invoice').'</th><td>'.ip_h($r->sales_invoice_no).'</td></tr><tr><th>'.fin_h('finance_bank', 'Bank').'</th><td>'.ip_h($r->bank_account.' - '.$r->bank_account_name).'</td><th>AR</th><td>'.ip_h($r->ar_account.' - '.$r->ar_account_name).'</td></tr><tr><th>'.fin_h('finance_amount', 'Amount').'</th><td class="text-right">'.ip_num($r->amount).' '.ip_h($r->currency).'</td><th>'.fin_h('common_status', 'Status').'</th><td>'.ip_h($r->status).'</td></tr><tr><th>'.fin_h('finance_description', 'Description').'</th><td colspan="3">'.ip_h($r->description).'</td></tr></table>';ip_json('success','OK',array('html'=>$html));break;
case 'excel':
  list($st,$en,$status,$cust)=ip_params();$excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Incoming Payment'));$headers=array(erp_export_label("No"),erp_export_label("Posting Date"),erp_export_label("Payment No"),erp_export_label("Customer"),erp_export_label("Invoice"),erp_export_label("Status"),erp_export_label("Bank"),erp_export_label("Method"),erp_export_label("Bank Ref"),erp_export_label("Amount"),erp_export_label("Currency"),erp_export_label("Journal"));foreach($headers as $i=>$h)$sheet->setCellValueByColumnAndRow($i,4,$h);$rows=ip_list($db,$st,$en,$status,$cust);$rn=5;$no=1;foreach($rows as $r){$vals=array($no++,$r->posting_date,$r->incoming_payment_no,$r->customer_code.' - '.$r->customer_name,$r->sales_invoice_no,$r->status,$r->bank_account.' - '.$r->bank_account_name,$r->payment_method,$r->bank_reference,$r->amount,$r->currency,$r->no_jurnal);foreach($vals as $i=>$v)$sheet->setCellValueByColumnAndRow($i,$rn,$v);$rn++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('INCOMING PAYMENT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rn-1),'column_count'=>count($headers),'money_columns'=>array('J'),'filters'=>array('Periode'=>$st.' s/d '.$en,'Status'=>$status,'Customer'=>$cust)));while(ob_get_level()>$initialOutputBufferLevel)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment;filename="incoming_payment_'.date('YmdHis').'.xlsx"');header('Cache-Control: max-age=0');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save('php://output');exit;
default:ip_json('error','Action tidak dikenal.');
}}catch(Exception $e){if(isset($db))$db->query("ROLLBACK");ip_json('error',$e->getMessage());}
